# Vlastní výjimky
class {{AppError}}(Exception):
    def __init__(self, message: str, code: int = 500):
        super().__init__({{message}})
        self.code = {{code}}

class ValidationError({{AppError}}):
    def __init__(self, field: str, message: str):
        super().__init__(f"Validation failed on '{{{field}}}': {message}", code=400)
        self.field = {{field}}

# Ošetření výjimek
def process_user_input(data: dict):
    try:
        age = int(data.get("age", ""))
        if age < 0 or age > 150:
            raise {{ValidationError}}("age", "must be 0-150")
        return {"age": {{age}}}
    except {{ValueError}}:
        raise ValidationError("age", "must be a number")
    except ValidationError:
        {{raise}}   # re-raise beze změny
    except Exception as e:
        raise AppError(f"Unexpected error: {e}") from {{e}}
    finally:
        print("Zpracování dokončeno")   # vždy se provede

// Vlastní výjimka
public class {{ValidationException}} extends RuntimeException {
    private final String field;
    public ValidationException(String field, String msg) {
        {{super}}(msg);
        this.{{field}} = field;
    }
    public String getField() { return {{field}}; }
}

// Ošetření výjimek
public int parseAge(String input) {
    try {
        int age = Integer.{{parseInt}}(input);
        if (age < 0 || age > 150) {
            throw new {{ValidationException}}("age", "must be 0-150");
        }
        return {{age}};
    } catch (NumberFormatException e) {
        throw new ValidationException("age", "must be a number");
    } catch (ValidationException e) {
        {{throw}} e;   // re-throw
    } finally {
        System.out.{{println}}("Zpracování dokončeno");
    }
}
